code_files.file:
{flake ? {}, ...}: let
  names = {
    src = "dots";
    top = "dots";
    lib = "lix";
  };

  paths = {
    store = {
      src = ./.;
      api = ./configuration/api;
      dbg = ./debug;
      documentation = ./documentation;
      configurations = ./configuration/modules;
      templates = ./templates;
      devShells = ./utilities/shells;
      utilities = ./utilities;
      secrets = ./configuration/secrets;
      libraries = ./libraries;
    };
    local.src = "/etc/nixos";
  };

  defaults.host = let
    inherit (builtins) isAttrs getEnv;
    env = {
      host = getEnv "HOSTNAME";
      name = getEnv "NAME";
    };
  in
    if isAttrs flake && (flake.currentHost or "") != ""
    then flake.currentHost
    else if env.host != ""
    then env.host
    else if env.name != ""
    then env.name
    else "ExampleHost";

  libraries =
    import paths.store.libraries
    {inherit defaults flake names paths;};
in
  # libraries
  libraries.mkSrc {inherit libraries;}

{
  description = "Configuration Flake";

  outputs = inputs: let
    defaults = {
      allowUnfree = true;
      nixpkgs = inputs.nixCore;
      excludes = let
        core = [
          "nixCore"
          "nixLegacy"
          "nixDarwin"
          "nixEdge"
        ];
      in {
        modules = core ++ ["treeFormatter" "treefmt"];
        overlays = core ++ ["nixHM" "home-manager"];
      };
    };

    src = import ./. {flake = {inherit defaults inputs;};};
  in
    {inherit src;}
    // src.lix.mkFlake
    src {
      configurations = true;
      utilities = true;
      devShells = true;
      templates = true;
    };

  inputs = {
    #~@ Core/Nix Infrastructure
    nixCore.url = "nixpkgs/nixos-unstable";
    nixLegacy.url = "nixpkgs/nixos-25.11";
    nixDarwin = {
      repo = "nix-darwin";
      owner = "LnL7";
      type = "github";
      inputs.nixpkgs.follows = "nixCore";
    };
    nixEdge = {
      ref = "nyxpkgs-unstable";
      repo = "nyx";
      owner = "chaotic-cx";
      type = "github";
      inputs = {
        nixpkgs.follows = "nixCore";
        home-manager.follows = "nixHM";
        rust-overlay.follows = "rust";
      };
    };
    nixHM = {
      repo = "home-manager";
      owner = "nix-community";
      type = "github";
      inputs.nixpkgs.follows = "nixCore";
    };

    #~@ Display/Window Managers
    compositorNiri = {
      repo = "niri-flake";
      owner = "sodiboo";
      type = "github";
      inputs.nixpkgs.follows = "nixCore";
    };

    #~@ Utilities:= formatting, tooling, secrets
    aiToolkit = {
      repo = "llm-agents.nix";
      owner = "numtide";
      type = "github";
      # inputs.nixpkgs.follows = "nixCore"; #? See llm-agents documentation
    };
    aiHermes = {
      repo = "hermes-agent";
      owner = "NousResearch";
      type = "github";
    };
    rust = {
      owner = "oxalica";
      repo = "rust-overlay";
      type = "github";
      inputs.nixpkgs.follows = "nixCore";
    };
    treeFormatter = {
      repo = "treefmt-nix";
      owner = "numtide";
      type = "github";
      inputs.nixpkgs.follows = "nixCore";
    };
    secretsManager = {
      repo = "sops-nix";
      owner = "Mic92";
      type = "github";
      inputs.nixpkgs.follows = "nixCore";
    };

    #~@ UI/UX:= shells, launchers, styling
    shellCaelestia = {
      repo = "shell";
      owner = "caelestia-dots";
      type = "github";
      inputs = {
        nixpkgs.follows = "nixCore";
        quickshell.follows = "shellQuick";
      };
    };
    shellDankMaterial = {
      # ref = "stable";
      repo = "DankMaterialShell";
      owner = "AvengeMedia";
      type = "github";
      inputs.nixpkgs.follows = "nixCore";
    };
    shellDankMaterialPlugins = {
      repo = "dms-plugin-registry";
      owner = "AvengeMedia";
      type = "github";
      inputs.nixpkgs.follows = "nixCore";
    };
    shellNoctalia = {
      repo = "noctalia-shell";
      owner = "noctalia-dev";
      type = "github";
      inputs.nixpkgs.follows = "nixCore";
    };
    shellQuick = {
      repo = "quickshell";
      owner = "outfoxxed";
      type = "github";
      inputs.nixpkgs.follows = "nixCore";
    };
    styleManager = {
      url = "github:nix-community/stylix";
      inputs.nixpkgs.follows = "nixCore";
    };

    #~@ Applications
    zenBrowser = {
      url = "github:0xc000022070/zen-browser-flake";
      inputs = {
        nixpkgs.follows = "nixCore";
        home-manager.follows = "nixHM";
      };
    };
    vicinae = {
      repo = "vicinae";
      owner = "vicinaehq";
      type = "github";
    };
  };
}

{
  bootstrap ? import ./internal/base,
  defaults ? {},
  flake ? {},
  names ? {},
  paths ? {},
}: let
  inherit (bootstrap.attrsets) merge removePaths;

  external = import ./external {
    inherit bootstrap defaults flake names paths;
  };

  internal = import ./internal {
    inherit bootstrap defaults external names paths;
  };
in
  removePaths (merge external internal) [
    {
      scopes = [
        "lib"
        "lists"
        "modules"
      ];
      items = [
        "applyModuleArgsIfFunction"
        "collectModules"
        "dischargeProperties"
        "evalOptionValue"
        "fold"
        "isInOldestRelease"
        "mergeModules'"
        "mergeModules"
        "mkAliasOptionModuleMD"
        "mkFixStrictness"
        "nixpkgsVersion"
        "pushDownProperties"
        "unifyModuleSyntax"
      ];
    }
  ]

{
  bootstrap ? import ../internal/base,
  defaults ? {allowUnfree = true;},
  flake ? {},
  inputs ? {},
  name ? null,
  names ? {src = "dots";},
  path ? null,
  paths ? {src = ../../.;},
}: let
  inherit (bootstrap.attrsets) merge;
  inherit (bootstrap.types) isFlakeLike isAttrs;
  inherit (bootstrap.config) getEnv;

  args = {
    inherit bootstrap;
    inherit (resolved) inputs;

    defaults = merge defaults (
      merge {
        host = let
          env = {
            host = getEnv "HOSTNAME";
            name = getEnv "NAME";
          };
        in
          if isAttrs flake && (flake.currentHost or "") != ""
          then flake.currentHost
          else if env.host != ""
          then env.host
          else if env.name != ""
          then env.name
          else "ExampleHost";

        excludes = {
          paths = [
            "archive"
            "backup"
            "review"
            "temp"

            "default.nix"
            "flake.nix"
          ];
        };

        tags = ["core" "home"];
      } (flake.defaults or {})
    );

    names = merge names (
      merge {
        src =
          if name != null
          then name
          else names.src;
      }
      (flake.names or {})
    );

    paths = merge paths (
      merge {
        store.src =
          if path != null
          then path
          else paths.src;
      } (flake.paths or{})
    );

    path = args.paths.store.src;
    name = args.names.src;
  };

  common = {
    inherit (args) defaults names paths;
    inherit (resolved) libraries;
  };

  resolved = {
    inputs = import ./inputs.nix {
      inputs = flake.inputs or inputs;
      inherit (args) bootstrap defaults name;
    };
    libraries = import ./libraries.nix args;
    modules = import ./modules.nix args;
    overlays = import ./overlays.nix args;
    packages = import ./packages.nix args;
  };

  src = {
    inherit common;
    flake = common // resolved;
  };
in
  {inherit (args) defaults names paths;}
  // resolved.libraries.merged
  // (
    if (isFlakeLike resolved.inputs)
    then {
      inherit (src) flake;
      ${args.names.src} = src.flake;
    }
    else {${args.names.src} = src.common;}
  )

{
  bootstrap,
  defaults,
  inputs,
  name,
  ...
}: let
  inherit (bootstrap) attrsets lists types;
  inherit (lists) isIn;
  inherit (attrsets) filter firstOf;
  inherit (types) hasLib hasModules hasOverlays isHomeManagerLike isNixDarwinLike isNixpkgsInfrastructure isNixpkgsLike isNotEmpty isTreefmtLike;

  raw =
    filter
    (input: _: !(isIn input ["self" name]))
    inputs;

  classified = {
    nixpkgs = filter (_: isNixpkgsLike) raw;
    nix-darwin = filter (_: isNixDarwinLike) raw;
    treefmt = filter (_: isTreefmtLike) raw;

    home-manager =
      filter
      (
        input: isHomeManagerLike
        # || input == "nixHM"
      )
      raw;

    modules =
      filter
      (
        input: value:
          hasModules value
          && !(isNixpkgsLike value)
        # && input != "nixHM"
      )
      raw;

    overlays = filter (_: hasOverlays) raw;

    packages =
      filter
      (_: value: value ? packages && !(isNixpkgsLike value))
      raw;

    libraries = filter (_: hasLib) raw;
    infrastructure = filter (_: isNixpkgsInfrastructure) raw;
  };

  normalized = {
    nixpkgs =
      if isNotEmpty (defaults.nixpkgs or {})
      then defaults.nixpkgs
      else firstOf classified.nixpkgs;

    nix-darwin = firstOf classified.nix-darwin;
    home-manager = firstOf classified.home-manager;
    treefmt = firstOf classified.treefmt;
  };

  merged = classified // normalized;
in {inherit raw classified normalized merged;}

{
  bootstrap,
  inputs,
  path,
  ...
}: let
  inherit (bootstrap) attrsets;
  inherit (attrsets) asIf filter maps orEmpty;

  classified =
    maps
    (_: input: input.lib)
    inputs.classified.libraries;

  treefmt = orEmpty inputs.normalized.treefmt;

  normalized =
    (
      maps
      (_: input: input.lib)
      (
        filter
        (_: value: value != null && value ? lib)
        inputs.normalized
      )
    )
    // {
      nixpkgs = let
        lib = inputs.normalized.nixpkgs.lib or (import <nixpkgs/lib>);
        inherit (lib) asserts attrsets debug filesystem lists strings trivial types;
      in
        lib
        // {
          filesystem =
            filesystem
            // {
              inherit (trivial) pathExists;
            };
        }
        // {
          debug =
            debug
            // {
              inherit (builtins) tryEval;
              inherit (asserts) assertMsg;
              inherit (trivial) deepSeq;
            };
        }
        // {
          lists =
            lists
            // (with lists; {
              firstList = findFirst;
              first = head;
              lastDropped = init;
              firstItem = head;
              lastItem = tail;
              itemFirst = head;
              itemLast = tail;
              itemIndexed = elemAt;
            });
        }
        // {
          types =
            types
            // {
              inherit (filesystem) isPath;
              inherit (attrsets) isAttrs isDerivation;
              inherit (trivial) isBool isFloat isFunction;
              inherit
                (strings)
                isConvertibleWithToString
                isInt
                isList
                isStorePath
                isString
                isStringLike
                isValidPosixName
                typeOf
                ;
            };
        };
    }
    // asIf (treefmt ? lib) {
      treefmt = treefmt.lib // {projectRoot = path;};
    };

  merged =
    normalized.nixpkgs
    // classified
    // normalized;
in {
  inherit classified normalized merged;
  scoped = normalized;
  global = merged;
}

{
  bootstrap,
  defaults,
  inputs,
  ...
}: let
  inherit (bootstrap) attrsets config lists;
  inherit (attrsets) filter isAttrs namesOf;
  inherit (config) collect;
  inherit (lists) asListIf isIn;

  excludes = defaults.excludes.modules or [];

  classified =
    filter
    (input: _: !(isIn input excludes))
    inputs.classified.modules;

  normalized = let
    mk = type: collect type classified;
  in {
    nixos = mk "nixos";
    darwin = mk "darwin";
    home = mk "home";
  };

  merged = classified // normalized;

  mkHM = type: let
    key =
      if type == "nixos"
      then "nixosModules"
      else if type == "darwin"
      then "darwinModules"
      else null;
    input = inputs.normalized.home-manager;
  in
    asListIf
    (
      (key != null)
      && (isAttrs input)
      && input ? ${key}.home-manager
    )
    input.${key}.home-manager;

  mkCore = type:
    asListIf
    (isIn type ["nixos" "darwin"])
    (
      [{nixpkgs.config = {inherit (defaults) allowUnfree;};}]
      ++ (mkHM type)
    );

  mkMods = type:
    if (isIn type (namesOf merged))
    then merged.${type} ++ (mkCore type)
    else throw "external.modules.mkMods: unknown type '${type}'";
in {inherit classified normalized excludes merged mkMods;}

{
  bootstrap,
  defaults,
  inputs,
  ...
}: let
  inherit (bootstrap) attrsets config lists;
  inherit (config) preferDefault;
  inherit (lists) concat elem;
  inherit (attrsets) filter maps valuesOf;

  excludes = defaults.excludes.overlays or [];

  raw =
    filter
    (input: _: !(elem input excludes))
    inputs.classified.overlays;

  classified =
    filter
    (_: value: value != {})
    (maps (_: input: input.overlays or {}) raw);

  normalized = {};
in {
  inherit raw classified normalized excludes;

  merged =
    concat
    (map preferDefault (valuesOf (classified // normalized)));
}

{
  bootstrap,
  inputs,
  ...
}: let
  inherit (bootstrap) attrsets config;
  inherit (config) getPackages;
  inherit (attrsets) asIf maps orEmpty;

  raw = inputs.classified.packages;

  classified =
    maps
    (_: getPackages)
    raw;

  normalized =
    asIf (inputs.normalized.nixpkgs != null) {
      nixpkgs = getPackages inputs.normalized.nixpkgs;
    }
    // asIf (inputs.normalized.home-manager != null) {
      home-manager = getPackages inputs.normalized.home-manager;
    };
in {
  inherit raw classified normalized;

  merged = classified // normalized;
  default = orEmpty normalized.nixpkgs;
}

{
  attrsets,
  debug,
  lists,
  strings,
  types,
  ...
}: let
  exports = {
    scoped = {
      inherit
        findFirst
        getBySpec
        getOrderedOr
        inspect
        inspectJSON
        isEmpty
        isNotEmpty
        mapOrdered
        mapParsedOrdered
        mergeUnique
        orDefault
        orEmpty
        orNull
        parseOrdered
        removeEmpty
        resolveBySpecs
        toOrdered
        ;
      dropNull = removeEmpty;
      merge = mergeUnique;
      orderedOf = toOrdered;
      parsedOf = parseOrdered;
    };
    global = {
      inspectAttr = inspect;
      inspectAttrJSON = inspectJSON;
      removeEmptyAttrs = removeEmpty;
      orNullAttr = orNull;
      orDefaultAttr = orDefault;
      orEmptyAttr = orEmpty;
      toOrderedAttrs = toOrdered;
      mapOrderedAttrs = mapOrdered;
      parseOrderedAttrs = parseOrdered;
      mapParsedOrderedAttrs = mapParsedOrdered;
      mergeUniqueAttrs = mergeUnique;
      getAttrBySpec = getBySpec;
      findFirstAttrs = findFirst;
      resolveAttrsBySpecs = resolveBySpecs;
      isEmptyAttr = isEmpty;
      isNotEmptyAttr = isNotEmpty;
    };
  };

  inherit (attrsets) attrNames filterAttrs hasAttr attrByPath getAttr listToAttrs mapAttrs optionalAttrs;
  inherit (lists) concatMap filter findFirstList foldl' genList isList length map nthOr;
  inherit (strings) concatStringsSep toJSON;
  inherit (debug) withContext;
  inherit (types) isAttrs typeOf isString isFunction' isPath;

  isEmpty = input: (input == null) || (isAttrs input && input == {});
  isNotEmpty = input: !isEmpty input;
  removeEmpty = sets: filterAttrs (_: value: (isNotEmpty value)) sets;

  orNull = input:
    assert withContext {
      name = "attrsets.orNull";
      assertion = types.isEmpty input || isAttrs input;
      message = "expected an attrset, got ${typeOf input}";
      context = "evaluating attrsets.orNull";
    };
      if types.isEmpty input || !(isAttrs input)
      then null
      else input;

  orDefault = default: input:
    assert withContext {
      name = "attrsets.orDefault";
      assertion = isAttrs default && isAttrs input;
      message = "expected attrsets, got default=${typeOf default} input=${typeOf input}";
      context = "evaluating attrsets.orDefault";
    };
      if isNotEmpty input
      then input
      else default;

  orEmpty = input:
    assert withContext {
      name = "attrsets.orEmpty";
      assertion = isNull input || isAttrs input;
      message = "expected an attrset or null, got ${typeOf input}";
      context = "evaluating attrsets.orEmpty";
    };
      optionalAttrs (isNotEmpty input) input;

  inspect = level: let
    fn = depth: value:
      if depth <= 0
      then "..."
      # else if builtins.isFunction value
      else if isFunction' value
      then "<function>"
      else if isPath value
      then "<path>"
      else if isList value
      then map (fn (depth - 1)) value
      else if isAttrs value
      then mapAttrs (_: fn (depth - 1)) value
      else value;
  in
    fn level;

  inspectJSON = level: value:
    toJSON (inspect level value);

  getBySpec = input: spec:
    assert withContext {
      name = "attrsets.getBySpec";
      assertion = isNull input || isAttrs input;
      message = "expected input to be an attrset or null, got ${typeOf input}";
      context = "evaluating attrsets.getBySpec";
    };
      if input == null
      then null
      else if isList spec
      then attrByPath spec null input
      else if isString spec && hasAttr spec input
      then getAttr spec input
      else null;

  findFirst = {
    sets,
    specs,
    default ? null,
  }:
    assert withContext {
      name = "attrsets.findFirst'";
      assertion = isList sets && isList specs;
      message = "expected sets and specs to be lists";
      context = "evaluating attrsets.findFirst";
    };
      findFirstList (x: x != null) default
      (concatMap (input: map (spec: getBySpec input spec) specs) sets);

  resolveBySpecs = {
    input,
    specs,
    default ? null,
  }:
    assert withContext {
      name = "attrsets.resolveBySpecs";
      assertion = (input == null || isAttrs input) && isList specs;
      message = "expected input to be an attrset or null, and specs to be a list";
      context = "evaluating attrsets.resolveBySpecs";
    };
      findFirst {
        sets = [input];
        inherit specs default;
      };

  mergeUnique = {
    items,
    attrs,
    what ? "attributes",
    owner ? (name: name),
  }:
    foldl'
    (
      acc: name: let
        incoming = attrs name;
        collisions = filter (k: hasAttr k acc) (attrNames incoming);
      in
        if collisions == []
        then acc // incoming
        else
          throw ''
            ${what}: collision(s) detected in '${owner name}':
              ${concatStringsSep ", " collisions}
            Each merged attribute name must be unique.
          ''
    )
    {}
    (attrNames items);

  getOrderedOr = {
    key,
    set,
    default ? null,
  }:
    if hasAttr key set
    then getAttr key set
    else default;

  toOrdered = {value}: let
    count =
      if isList value
      then length value
      else 1;
  in
    listToAttrs (
      map (position: {
        name = toString (position + 1);
        value = nthOr {
          inherit position value;
        };
      }) (genList (x: x) count)
    );

  mapOrdered = set:
    mapAttrs (_: value: toOrdered {inherit value;}) set;

  parseOrdered = value: let
    ordered =
      if isAttrs value
      then value
      else toOrdered {inherit value;};

    primary = getOrderedOr {
      key = "1";
      set = ordered;
    };
    secondary = getOrderedOr {
      key = "2";
      set = ordered;
    };
    tertiary = getOrderedOr {
      key = "3";
      set = ordered;
    };

    preferred = primary;
    fallback = secondary;

    default =
      if isList value
      then
        if value == []
        then null
        else
          nthOr {
            position = (length value) - 1;
            inherit value;
          }
      else if isAttrs value
      then
        getOrderedOr {
          key = "default";
          set = value;
          default = primary;
        }
      else value;
  in
    ordered
    // {inherit primary secondary tertiary preferred fallback default;};

  mapParsedOrdered = set: mapAttrs (_: parseOrdered) set;
in
  exports

{
  strings,
  types,
  lists,
  ...
}: let
  exports = {
    scoped = {
      inherit
        as
        asIf
        firstOf
        fromList
        get
        gets
        gets'
        has
        inspect
        is
        maps
        merge
        namesOf
        orEmpty
        orEmpty'
        removePath
        removePaths
        select
        valuesOf
        ;
      filter = select;
      getFirst = firstOf;
      orEmptyNamed = orEmpty';
      inherit (builtins) isAttrs;
    };

    global = {
      asAttrs = as;
      asAttrsIf = asIf;
      filterAttrs = select;
      findFirstAttr = firstOf;
      getAttrs = gets;
      getAttrsSafe = gets;
      inheritAttr = orEmpty';
      inspectAttrs = inspect;
      orEmptyAttrs = orEmpty;
      recursiveUpdate = merge;
      recursiveAttrs = merge;
      removeAttrPaths = removePaths;
      removeAttrPath = removePath;
    };
  };

  inherit (builtins) concatMap head filter foldl' isFunction isAttrs isList isString tail typeOf;
  namesOf = builtins.attrNames;
  valuesOf = builtins.attrValues;
  get = builtins.getAttr;
  has = builtins.hasAttr;
  is = builtins.isAttrs;
  fromList = builtins.listToAttrs;
  intersect = builtins.intersectAttrs;
  maps = builtins.mapAttrs;

  inherit (lists) asList;
  inherit (strings) concat split;
  inherit (types) isNotEmpty;

  /**
  Normalize raw path inputs into consistent lists of split string segments.
  Accepts flat strings, lists of segments, or a matrix set containing `scopes` and `items`.

  Options for matrix sets:
    - root:  boolean (default: true). Unconditionally checks the root scope.
    - exact: boolean (default: false). If true, disables full permutation generation
             and treats the provided `scopes` as literal, exact paths.

  Example:
    normalizePaths [ { scopes = ["lib.lists"]; items = ["fold"]; exact = true; } ]
    # => [ ["fold"] ["lib" "lists" "fold"] ]
  */
  normalizePaths = args:
    concatMap (
      entry:
        if isAttrs entry && entry ? scopes && entry ? items
        then let
          permutations = list:
            if list == []
            then [[]]
            else
              concatMap (
                element:
                  map (
                    perm: [element] ++ perm
                  ) (permutations (filter (candidate: candidate != element) list))
              )
              list;

          prefixes = list:
            if list == []
            then []
            else
              [[(head list)]]
              ++ map (perm: [(head list)] ++ perm) (prefixes (tail list));

          scopeStrings =
            (
              if (entry.root or true)
              then [""]
              else []
            )
            ++ (
              if (entry.exact or false)
              then entry.scopes
              else
                map
                (concat ".")
                (concatMap prefixes (permutations entry.scopes))
            );
        in
          concatMap (
            scope:
              map (
                item:
                  split "." (
                    if scope == ""
                    then item
                    else "${scope}.${item}"
                  )
              )
              entry.items
          )
          scopeStrings
        else if isList entry
        then asList entry
        else asList (split "." entry)
    ) (
      if isAttrs args && args ? paths
      then args.paths
      else args
    );

  /**
  Recursively traverses an attribute set to remove a single pre-segmented path.
  Matches the native `removeAttrs` input style: (set -> path).

  Example:
    removePath { lib = { lists = { fold = ...; }; }; } [ "lib" "lists" "fold" ]
  */
  removePath = set: list:
    if !isAttrs set || list == []
    then set
    else let
      path = {
        initial = head list;
        remaining = tail list;
      };
    in
      if path.remaining == []
      then removeAttrs set [path.initial]
      else if set ? ${path.initial}
      then set // {${path.initial} = removePath set.${path.initial} path.remaining;}
