        inherit (user) description;
        group = user.group or user.name;
        isNormalUser = (user.role or "") != "service";
        isSystemUser = (user.role or "") == "service";
        extraGroups =
          if user.role == "administrator"
          then ["networkmanager" "wheel"]
          else if user.role == "service"
          then ["networkmanager"]
          else [];
      })
      principals;

    groups = mapAttrs (_: user: {}) principals;
  };

  /**
  Generate Home Manager targets for all interactive users tracked by the host.
  */
  mkHomeUsers = {
    lib,
    host,
    dom,
    mod,
  }: let
    byName = collectNamedSpecs {
      args = {inherit host lib dom mod;};
      base = mod;
    };
  in
    mapAttrs (
      name: user:
        mkHomeUser (byName.${name} or {})
    ) (getNonService host);

  /**
  UNIFIED RULE: Generates a Home Manager configuration layout for an individual user profile.
  Automatically merges system-wide flake paths with user-specific custom paths.
  */
  mkHomeUser = spec: {
    config,
    osConfig,
    top,
    src,
    ...
  }: let
    paths = let
      flake = osConfig.${top}.paths.local or {};
      host = listToAttrs (map (name: {
        name = concat "_" [src.name name];
        value = flake.${name};
      }) (namesOf flake));
      user = orEmpty spec.paths;
    in {
      inherit host user;
      merged = host // user;
      resolved = config.${top}.paths.local;
    };
  in {
    imports =
      [
        {
          ${top}.paths.local = paths.merged;
          home = {
            sessionVariables = mkVariables paths.config;
            shellAliases = mkCdAliases paths.config;
          };
          programs.home-manager.enable = true;
        }
        (
          optionalAttrs
          (osConfig ? system.stateVersion)
          {home = {inherit (osConfig.system) stateVersion;};}
        )
      ]
      ++ asList (spec.home or null);
  };

  mkSudoRules = host:
    map (user: {
      users = [user.name];
      commands = [
        {
          command = "ALL";
          options = ["SETENV" "NOPASSWD"];
        }
      ];
    }) (valuesOf (getAdmins host));

  /**
  Reads your active host users and injects their respective operating system core modules.
  */
  collectImports = {
    host,
    top,
    base,
  }: let
    byName = collectNamedSpecs {
      args = {inherit top host;};
      inherit base;
    };
  in
    concatMap (
      user: let
        spec = byName.${user.name} or {};
      in
        asList (spec.core or null)
    ) (valuesOf (getNonService host));
in
  exports

{
  debug,
  types,
  strings,
  ...
}: let
  exports = {
    scoped = {
      inherit
        mkTest
        mkTest'
        mkThrows
        assertMsgFunc
        assertWithContext
        warnWithContext
        expect
        ;
      withContext = assertWithContext;
    };
    global = {
      inherit
        assertWithContext
        expect
        warnWithContext
        ;
    };
  };

  inherit (debug) addErrorContext assertMsg deepSeq traceIf tryEval;
  inherit (types) isAttrs isBool isPath isString typeOf;
  inherit (strings) toJSON;

  assertMsgFunc = {
    name,
    assertion,
    message,
  }:
    assertMsg assertion "${name}: ${message}";

  assertWithContext = {
    name,
    assertion,
    message,
    context,
  }:
    addErrorContext
    "while ${context}"
    (assert assertMsgFunc {
      inherit name assertion message;
    }; true);

  _build = desired: outcome: command: let
    value = deepSeq outcome outcome;
  in {
    inherit desired command;
    result = value;
    passed = desired == value;
  };

  warnWithContext = {
    name,
    assertion,
    message,
    context,
  }:
    deepSeq
    (traceIf (!assertion) "[${name}] while ${context}: ${message}" true)
    assertion;

  /**
  Create a named test case with desired output, outcome expression, and an
  optional command string for display in test results.

  # Type
  ```nix
  mkTest :: { desired :: a, outcome :: a, command :: string? } -> Test
  ```

  # Examples
  ```nix
  mkTest {
    desired = "foo-bar";
    command = ''normalize "Foo Bar"'';
    outcome = normalize "Foo Bar";
  }
  ```
  */
  mkTest = {
    desired,
    outcome,
    command ? null,
  }:
    _build desired outcome command;

  /**
  Positional shorthand for `mkTest` - no command string.

  Useful in enum and validator test blocks where the expression is self-evident.

  # Type
  ```nix
  mkTest' :: a -> a -> Test
  ```

  # Examples
  ```nix
  validatesRust = mkTest' true  (languages.validator.check "rust")
  correctCount  = mkTest' 4     (length cpuBrands.values)
  ```
  */
  mkTest' = desired: outcome: _build desired outcome null;

  /**
  Create a test case that expects evaluation to throw.

  Uses `builtins.tryEval` to catch the error - the test passes only if
  evaluation fails.

  # Type
  ```nix
  mkThrows :: a -> Test
  ```

  # Examples
  ```nix
  mkThrows (validate { fnName = "f"; argName = "x"; desired = "set"; predicate = isAttrs; outcome = "oops"; })
  ```
  */
  mkThrows = outcome:
    mkTest {
      desired = {
        success = false;
        value = false;
      };
      outcome = tryEval outcome;
    };

  expect = {
    type,
    value,
    context,
    name,
  }:
    assert assertWithContext {
      inherit name context;
      assertion =
        if type == "bool"
        then isBool value
        else if type == "attrs"
        then isAttrs value
        else if type == "path"
        then (isPath value || (isString value && value != ""))
        else false;
      message = "Expected type '${type}', but got '${typeOf value}' with value: ${toJSON value}";
    }; value;
in
  exports

{
  bootstrap ? import ./base,
  external ? import ../external {},
  paths ? {},
  defaults ? {},
  names ? {},
}: let
  inherit (bootstrap) foldl' mkLibs recursiveAttrs recursiveSelf;

  flake = external.flake or {};

  resolved = {
    defaults = recursiveAttrs defaults (
      recursiveAttrs {
        host = "ExampleHost";
        excludes.paths = [
          "archive"
          "backup"
          "review"
          "temp"
          "default.nix"
          "flake.nix"
        ];
        tags = ["core" "home"];
      }
      (flake.defaults or {})
    );

    paths = recursiveAttrs paths (
      recursiveAttrs {
        store = {
          src = ../../.;
          api = ../../configuration/api;
        };
        local.src = "/etc/nixos";
      }
      (flake.paths or {})
    );

    names = recursiveAttrs names (
      recursiveAttrs {
        src = "dots";
        lib = "lix";
        top = "_";
      }
      (flake.names or {})
    );
  };

  mk = {
    input,
    output ? [],
    dependencies ? [
      "api"
      "attrsets"
      "config"
      "debug"
      "defaults"
      "environment"
      "external"
      "flake"
      "lists"
      "names"
      "options"
      "paths"
      "strings"
      "systems"
      "types"
    ],
  }: {inherit input dependencies output;};

  scoped = recursiveSelf (libraries:
    mkLibs {
      libraries =
        recursiveAttrs
        (recursiveAttrs external bootstrap)
        (
          libraries
          // {
            inherit (resolved) defaults names paths;
            flake = flake;
            external = external;
          }
        );

      specs = [
        (mk {
          input = resolved.paths.store.api;
          output = ["api"];
        })
        (mk {input = ./attrsets.nix;})
        (mk {input = ./debug.nix;})
        (mk {input = ./filesystem.nix;})
        (mk {input = ./lists.nix;})
        (mk {input = ./options.nix;})
        (mk {input = ./strings.nix;})
        (mk {input = ./types.nix;})
        (import ./config)
      ];
    });

  global = foldl' (acc: name: acc // (scoped.${name}.global or {})) {} [
    "api"
    "attrsets"
    "debug"
    "filesystem"
    "lists"
    "options"
    "strings"
    "types"
    "config"
  ];

  merged = recursiveAttrs scoped global;
in
  merged
  // {
    lib = external;
    "${resolved.names.lib}" = merged;
  }

{
  attrsets,
  lists,
  strings,
  ...
}: let
  exports = {
    scoped = {inherit entrypoint entrypoints;};
    global = {inherit entrypoint entrypoints;};
  };

  # inherit (debug) withContext;
  inherit (lists) head;
  inherit (attrsets) mapAttrs;
  inherit (strings) stringLength substring;

  entrypoints.nix = let
    ext = "nix";
    candidates = map (name: "${name}.${ext}") [
      "default"
      "shell"
      "flake"
      "configuration"
      "_"
    ];
    primary = head candidates;
  in {inherit ext candidates primary;};
  entrypoint = entrypoints.nix.primary;

  /**
  Maps a set of pure store paths into absolute local path strings relative to local.src
  */
  mapStoreToLocal = {
    store,
    localSrc,
  }: let
    storeRoot = toString store.src;
    rootLength = stringLength storeRoot;
  in
    mapAttrs (
      _: path: let
        pathStr = toString path;
        # Strip out the base store path prefix to capture the relative subpath
        relSubpath = substring rootLength (-1) pathStr;
      in "${localSrc}${relSubpath}"
    )
    store;
in
  exports

{
  attrsets,
  debug,
  lists,
  types,
  ...
}: let
  exports = {
    scoped = {
      inherit asList nthOr orNull orDefault orEmpty;

      atOr = nthOr;
      has = has';
      hasAny = hasAny';
      isEmpty = isEmpty';
      isNotEmpty = isNotEmpty';
    };
    global = {
      isEmptyList = isEmpty';
      isNotEmptyList = isNotEmpty';
      orDefaultList = orDefault;
      orNullList = orNull;
      toList' = asList;
      valueInList = nthOr;

      # Added to global exports
      inList = has';
      anyInList = hasAny';
    };
  };

  inherit (attrsets) isAttrs;
  inherit (debug) assertWithContext;
  inherit (lists) elemAt isList length optionals toList any elem; # Inherited 'any' and 'elem'
  inherit (types) typeOf isEmpty;

  isEmpty' = value: value == [];
  isNotEmpty' = value: !isEmpty' value;

  # --- Membership Checks ---

  has' = item: list:
    assert assertWithContext {
      name = "lists.has";
      assertion = isList list;
      message = "expected a list to search within, got ${typeOf list}";
      context = "evaluating lists.has";
    };
      elem item list;

  hasAny' = candidates: list:
    assert assertWithContext {
      name = "lists.hasAny";
      assertion = isList list;
      message = "expected a target list to search within, got ${typeOf list}";
      context = "evaluating lists.hasAny";
    };
      any (candidate: elem candidate list) (asList candidates);

  # --- Existing Methods ---

  orNull = value:
    assert assertWithContext {
      name = "lists.orNull";
      assertion = isEmpty value || isList value;
      message = "expected a list, got ${typeOf value}";
      context = "evaluating lists.orNull";
    };
      if isEmpty value || !(isList value)
      then null
      else value;

  orDefault = default: value:
    assert assertWithContext {
      name = "lists.orDefault";
      assertion = isList default && isList value;
      message = "expected lists, got default=${typeOf default} value=${typeOf value}";
      context = "evaluating lists.orDefault";
    };
      if isNotEmpty' value
      then value
      else default;

  orEmpty = value:
    assert assertWithContext {
      name = "lists.orEmpty";
      assertion = value == null || isList value;
      message = "expected a list or null, got ${typeOf value}";
      context = "evaluating lists.orEmpty";
    };
      optionals (isNotEmpty' value) value;

  asList = val: optionals (val != null) (toList val);

  nthOr = input: let
    fromArgs = {
      position,
      value,
      default ? null,
    }:
      if isList value
      then
        if length value > position
        then elemAt value position
        else default
      else if position == 0
      then value
      else default;
  in
    if isAttrs input
    then fromArgs input
    else
      position:
        fromArgs {
          value = input;
          inherit position;
        };
in
  exports

{
  attrsets,
  lists,
  options,
  types,
  ...
}: let
  exports = {
    scoped = {
      inherit
        mkEnable
        mkCfg
        mkOpt
        mkEnableMod
        mkModuleArgs
        mkFloatOption
        mkLatitudeOption
        mkLongitudeOption
        mkGeoProviderOption
        mkTimezoneOption
        mkLocalTimeOption
        mkLocaleOption
        ;
    };
    global = {inherit mkModuleArgs;};
  };

  inherit (attrsets) attrByPath setAttrByPath optionalAttrs;
  inherit (lists) asList hasAny;
  inherit (options) mkOption mkEnableOption;
  inherit (types) nullOr addCheck float str;

  mkEnable = {
    name ? null,
    mod ? null,
    description ? null,
    scope ? "core",
  }: let
    module =
      if name != null && name != ""
      then name
      else if mod != null && mod != ""
      then mod
      else null;

    description' =
      if description != null
      then description
      else if module != null
      then "Whether ${module} should be enabled ${
        if scope == "core"
        then "system-wide"
        else if scope == "home"
        then "for the user"
        else throw "Expected scope to be one of [core home], got ${scope}"
      }"
      else "Whether to enable this module";
  in {
    false = mkEnableOption description';
    true = mkEnableOption description' // {default = true;};
  };

  mkCfg = {
    config,
    path,
  }:
    attrByPath (asList path) {} config;

  mkOpt = {
    options,
    path,
  }:
    setAttrByPath (asList path) options;

  mkEnableMod = {
    mod,
    scope,
  }:
    mkEnable {inherit mod scope;};

  mkModuleArgs = {
    config,
    top,
    dom,
    mod,
    host ? {},
    scope ? "core",
  }: let
    path = [top dom mod];
  in {
    inherit host top config scope;
    cfg = mkCfg {inherit config path;};
    opt = options: mkOpt {inherit options path;};
    base = mod;
    mkEnableMod = mkEnableMod {inherit mod scope;};
  };

  mkFloatOption = {
    description,
    min ? null,
    max ? null,
    default ? null,
  }: let
    check = value:
      (
        if min != null
        then value >= min
        else true
      )
      && (
        if max != null
        then value <= max
        else true
      );
  in
    mkOption ({
        type = nullOr (addCheck float check);
        inherit description;
      }
      // optionalAttrs (default != null) {inherit default;});

  mkLatitudeOption = {
    host,
    default ? null,
  }:
    mkFloatOption {
      description = "Latitude coordinate, between -90.0 and 90.0";
      min = -90.0;
      max = 90.0;
      default = host.localization.latitude or default;
    };

  mkLongitudeOption = {
    host,
    default ? null,
  }:
    mkFloatOption {
      description = "Longitude coordinate, between -180.0 and 180.0";
      min = -180.0;
      max = 180.0;
      default = host.localization.longitude or default;
    };

  mkGeoProviderOption = {
    host,
    default ? "manual",
  }: let
    loc = host.localization or {};
    provider = loc.provider or null;
    latitude = loc.latitude or null;
    longitude = loc.longitude or null;
  in
    mkOption {
      type = types.enum ["manual" "geoclue2"];
      description = "Location provider. If 'manual', valid latitude and longitude must be provided.";
      default =
        if provider != null
        then provider
        else if latitude != null && longitude != null
        then default
        else "geoclue2";
    };

  mkTimezoneOption = {
    host,
    default ? null,
  }:
    mkOption ({
        type = nullOr str;
        description = "The system or user timezone.";
      }
      // optionalAttrs (host.localization.timezone or default != null) {
        default = host.localization.timezone or default;
      });

  mkLocalTimeOption = {host}: let
    useLocalTime =
      hasAny
      ["dual-boot" "dualboot-windows"]
      (host.functionalities or []);
  in
    mkEnableOption ''
      Keeps the hardware clock in local time instead of UTC.
      This is particularly important when the system dual-boots with Windows,
      as Windows defaults to local time for the RTC.
    ''
    // {default = useLocalTime;};

  mkLocaleOption = {
    host,
    default ? "en_US.UTF-8",
  }:
    mkOption {
      type = str;
      description = ''
        Configures the default locale settings. This determines:
        - Language for program messages and UI text.
        - Date, time, numeric, and monetary formatting conventions.
        - Character sorting and collation order.

        Applies to all applications that respect locale environment variables.
      '';
      default = host.localization.locale or default;
    };
in
  exports

{
  debug,
  lists,
  strings,
  types,
  ...
}: let
  exports = {
    scoped = {
      inherit
        _applyStr
        _normalizeSymbols
        _splitWords
        capitalize
        indent
        normalize
        orDefault
        orEmpty
        orNull
        replaceAll
        toCamel
        toLower'
        toPascal
        toScreamingSnake
        toSnake
        toTitle
        toUpper'
        trim'
        trimEnd
        trimStart
        wrap
        ;
      trim = trim';
      isEmpty = isEmpty';
      isNotEmpty = isNotEmpty';
    };
    global = {
      inherit
        capitalize
        indent
        normalize
        replaceAll
        toCamel
        toLower'
        toPascal
        toScreamingSnake
        toSnake
        toTitle
        toUpper'
        trim'
        trimEnd
        trimStart
        wrap
        ;
      capitalizeString = capitalize;
      isEmptyString = isEmpty';
      isNotEmptyString = isNotEmpty';
      normalizeString = normalize;
      orDefaultString = orDefault;
      orEmptyString = orEmpty;
      orNullString = orNull;
      quote = wrap;
      quoteString = wrap;
      replaceAllStrings = replaceAll;
      toCamelCase = toCamel;
      toLowerCase = toLower';
      toPascalCase = toPascal;
      toScreamingSnakeCase = toScreamingSnake;
      toSnakeCase = toSnake;
      toTitleCase = toTitle;
      toUpperCase = toUpper';
      trimString = trim';
      trimStringEnd = trimEnd;
      trimStringStart = trimStart;
    };
  };

  inherit (lists) head tail genList asList any;
  inherit (debug) withContext;
  inherit (types) isEmpty isNotEmpty isList isAttrs isString typeOf;
  inherit (strings) concatStrings concatStringsSep hasPrefix hasSuffix optionalString removePrefix removeSuffix replaceStrings splitString stringLength substring toLower toUpper;

  isEmpty' = value: value == "";
  isNotEmpty' = value: !isEmpty' value;

  orNull = value:
    assert withContext {
      name = "strings.orNull";
      assertion = isEmpty value || isString value;
      message = "expected a string, got ${typeOf value}";
      context = "evaluating strings.orNull";
    };
      if isEmpty value || !(isString value)
      then null
      else value;

  orDefault = default: value:
    assert withContext {
      name = "strings.orDefault";
      assertion = isString default && isString value;
      message = "expected strings, got default=${typeOf default} value=${typeOf value}";
      context = "evaluating strings.orDefault";
    };
      if isNotEmpty' value
      then value
      else default;

  orEmpty = value:
    assert withContext {
      name = "strings.orEmpty";
      assertion = value == null || isString value;
      message = "expected a string or null, got ${typeOf value}";
      context = "evaluating strings.orEmpty";
    };
